bool Media::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("type"))
    {
        if(!validJsonOfField(1, "type", pJson["type"], err, true))
            return false;
    }
    else
    {
        err="The type column cannot be null";
        return false;
    }
    if(pJson.isMember("title"))
    {
        if(!validJsonOfField(2, "title", pJson["title"], err, true))
            return false;
    }
    if(pJson.isMember("url"))
    {
        if(!validJsonOfField(3, "url", pJson["url"], err, true))
            return false;
    }
    else
    {
        err="The url column cannot be null";
        return false;
    }
    if(pJson.isMember("thumbnail"))
    {
        if(!validJsonOfField(4, "thumbnail", pJson["thumbnail"], err, true))
            return false;
    }
    if(pJson.isMember("sort_order"))
    {
        if(!validJsonOfField(5, "sort_order", pJson["sort_order"], err, true))
            return false;
    }
    if(pJson.isMember("is_active"))
    {
        if(!validJsonOfField(6, "is_active", pJson["is_active"], err, true))
            return false;
    }
    if(pJson.isMember("uploaded_by"))
    {
        if(!validJsonOfField(7, "uploaded_by", pJson["uploaded_by"], err, true))
            return false;
    }
    if(pJson.isMember("created_at"))
    {
        if(!validJsonOfField(8, "created_at", pJson["created_at"], err, true))
            return false;
    }
    return true;
}
